const store = $getWorkflowStaticData('global');

if (!store.seen) {
  store.seen = {};
}

const now = Date.now();
const ttl = 15 * 60 * 1000; // 15 min

// limpiar viejos
for (const k in store.seen) {
  if (now - store.seen[k] > ttl) {
    delete store.seen[k];
  }
}

// normalizar texto
const raw = String($json.extracted_text || '')
  .toLowerCase()
  .trim()
  .replace(/\s+/g, ' ')
  .replace(/[^a-z0-9\u00C0-\u024F\u0400-\u04FF\s@+.-]/gi, '');

// si no hay texto → no duplicado
if (!raw) {
  return [{ ...$json, isDuplicate: false }];
}

// 🧠 hash simple (sin crypto)
let hash = 0;

for (let i = 0; i < raw.length; i++) {
  hash = ((hash << 5) - hash) + raw.charCodeAt(i);
  hash |= 0; // convertir a 32bit
}

const key = String(hash);

// check duplicado
if (store.seen[key]) {
  return [{ ...$json, isDuplicate: true }];
}

// guardar
store.seen[key] = now;

return [{ ...$json, isDuplicate: false }];

const text = ($json.extracted_text || '')
  .toLowerCase()
  .trim();

const normalized = text
  .replace(/\s+/g, ' ')
  .replace(/[^a-z0-9\u00C0-\u024F\u0400-\u04FF\s@+.-]/gi, '');

const weakPatterns = ['hola', 'gracias', 'info', 'ok', 'hi', 'hello', 'thanks', 'info', 'ok', 'oi', 'ola', 'obrigado', 'info', 'привет', 'спасибо', 'инфо'];
const strongSignals = ['plaza', 'busco', 'ofrezco', 'spot', 'looking', 'available', 'offer', 'vaga', 'procuro', 'ofereço', 'место', 'ищу', 'предлагаю', 'evento', 'fiesta', 'club', 'hotel', 'event', 'party', 'club', 'festival', 'evento', 'festa', 'balada', 'ивент', 'вечеринка', 'клуб', 'hoy', 'mañana', 'today', 'tomorrow', 'сегодня', 'завтра', 'hoje', 'amanhã', 'ibiza', 'dubai', 'madrid', 'barcelona', 'milan', 'paris', 'london', 'telegram', 'whatsapp', 'contact', 'контакт'];

let score = 0;
if (normalized.length >= 12) score += 1;
if (normalized.length >= 25) score += 1;
if (/\d/.test(normalized)) score += 1;
if (/@|\+?\d{6,}/.test(normalized)) score += 2;
if (strongSignals.some(s => normalized.includes(s))) score += 3;
if (weakPatterns.includes(normalized)) score -= 3;
if ((normalized.match(/https?:\/\//g) || []).length > 1) score -= 2;
const repeated = /(.)\1{4,}/.test(normalized);
if (repeated) score -= 2;
if (normalized.split(' ').length <= 2) score -= 2;
const looksValuable = score >= 3 || (score >= 2 && normalized.length > 30);

return [{
  ...$json,
  prefilter_score: score,
  looksValuable,
  normalized_text: normalized
}];

let content;
try {
  content = JSON.parse($input.first().json.choices?.[0]?.message?.content || '{}');
} catch (e) {
  return [{ trash: true, parse_error: true, raw: $input.first().json }];
}
return [{
  trash: content.trash ?? false,
  category: content.category ?? '',
  type: content.type ?? '',
  subtype: content.subtype ?? '',
  continent: content.continent ?? '',
  country: content.country ?? '',
  city: content.city ?? '',
  budget: content.budget ?? '',
  contact: content.contact ?? '',
  text_es: content.text_es ?? '',
  text_en: content.text_en ?? '',
  text_ru: content.text_ru ?? '',
  text_pt: content.text_pt ?? ''
}];

const validCategories = ['plaza', 'evento'];
const validTypes = ['ofrezco_plaza', 'busco_plaza', 'evento'];
const category = $json.category ?? '';
const type = $json.type ?? '';
const subtype = $json.subtype ?? '';
let coherent = true;
if (category === 'plaza' && !['ofrezco_plaza', 'busco_plaza'].includes(type)) { coherent = false; }
if (category === 'evento' && type !== 'evento') { coherent = false; }
return [{
  ...$json,
  subtype,
  trash: $json.trash === true || !validCategories.includes(category) || !validTypes.includes(type) || !coherent
}];

let score = 0;
if ($json.city) score += 1;
if ($json.country) score += 1;
if ($json.type === 'ofrezco_plaza') score += 2;
if ($json.type === 'busco_plaza') score += 1;
if ($json.category === 'evento') score += 2;
if ($json.budget) score += 2;
if ($json.contact) score += 2;
if ($json.text_es && $json.text_es.length > 40) score += 1;
if ($json.trash) score -= 5;
return [{ ...$json, score }];
